/**
 * Dynamic Extension Loader
 * 
 * Allows loading extensions by path after pi is already running.
 * Usage: /load-extension <path-to-extension>
 */

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { resolve } from "node:path";
import { existsSync } from "node:fs";

export default function dynamicLoaderExtension(pi: ExtensionAPI) {
  pi.registerCommand("load-extension", {
    description: "Dynamically load an extension by path",
    handler: async (args: string, ctx: ExtensionContext) => {
      if (!args || args.trim() === "") {
        ctx.ui.notify("Usage: /load-extension <path-to-extension>", "warning");
        return;
      }

      const extensionPath = resolve(args.trim());

      if (!existsSync(extensionPath)) {
        ctx.ui.notify(`Extension not found: ${extensionPath}`, "error");
        return;
      }

      try {
        // Note: Pi doesn't support dynamic loading after startup via API
        // This is a conceptual example - actual implementation would require
        // modifying pi's core or using /reload with auto-discovery paths
        ctx.ui.notify(
          `To load ${extensionPath}, place it in ~/.pi/agent/extensions/ and use /reload`,
          "info"
        );

        // Alternative: suggest copying to auto-discover location
        ctx.ui.notify(
          `Or copy it: cp ${extensionPath} ~/.pi/agent/extensions/ && /reload`,
          "info"
        );
      } catch (error) {
        ctx.ui.notify(`Failed to load extension: ${error}`, "error");
      }
    },
  });

  pi.registerCommand("extensions-info", {
    description: "Show information about dynamic loading",
    handler: async (_args: string, ctx: ExtensionContext) => {
      ctx.ui.notify(
        "To load extensions dynamically:\n" +
        "1. Copy extension to ~/.pi/agent/extensions/\n" +
        "2. Use /reload to load it\n" +
        "Or restart pi with: pi -e <path-to-extension>",
        "info"
      );
    },
  });
}

